practice.code:
const nums: number[] = [3, 15, 7, 20, 4, 12];
// YOUR CODE HERE
// Filter > 10, map to squares, print result

solutionCode:
const nums: number[] = [3, 15, 7, 20, 4, 12];
const result = nums.filter(n => n > 10).map(n => n * n);
console.log(JSON.stringify(result));

